var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"큭!","JPN":"くっ！","ENG":"Kgh!","TWN":"唔！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"지난번보다 더 매서운 공격이다.","JPN":"前回より攻撃が強い。","ENG":"Its attack is fiercer than before.","TWN":"這次的攻擊比上次更猛烈。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"이대론 얼마나 견딜 수 있을지…….","JPN":"これでは、はたしてどのくらい持つか……","ENG":"I don't know how much longer I can endure it...","TWN":"這樣下去不知道能撐多久……"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"작전은 간단합니다. 당신과 토벌대가 공격을 받아내는 동안, 저는 포격을 하는 거죠.","JPN":"作戦は単純です。あなたと討伐隊が交戦している間、私が砲撃するのです。","ENG":"The operation is simple. While you and the extermination team repel the C.O.'s attacks, I will start the bombardment.","TWN":"作戰很簡單。在你和討伐隊擋住攻擊的同時，我會進行炮擊。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"에스타크는 이론상 4종 침식체도 잡아낼 수 있는 병기입니다.","JPN":"エスタークは設計上、第4種侵食体も倒せるようにできています。","ENG":"Estaque is a weapon that can theoretically take out Category 4 C.O.s.","TWN":"艾斯塔克理論上是能夠有效殺傷4類侵蝕體的兵器。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"전설 속의 침식체가 얼마나 대단한지는 모르겠지만, 분명 타격을 입을 테죠.","JPN":"伝説の侵食体がどんなものかはわかりませんが、きっとダメージを与えることができるはずです。","ENG":"I don't know how strong the legendary C.O. is, but I'm certain it will deal some damage to it.","TWN":"我不知道傳說中的侵蝕體有多厲害，但肯定會受傷的。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"주변의 침식파 밀도가 높아지고 있습니다.","JPN":"周辺の侵食波密度が上昇しています。","ENG":"The nearby Corruption ray density is rising.","TWN":"周圍的侵蝕波密度正在上升。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"녀석이 <color=#ffd34c>미끼</color>를 문 모양이군요.","JPN":"奴が<color=#ffd34c>餌</color>に食らいついた証拠です。","ENG":"It seems that it has taken the <color=#ffd34c>bait</color>.","TWN":"那傢伙似乎<color=#ffd34c>上鉤</color>了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"미끼? 그 침식체를 불러낼 수 있는 방법을 알고 있었단 말이야?","JPN":"餌だと？　侵食体を呼び込む術を知っているのか？","ENG":"Bait? You knew a way to lure that C.O.?","TWN":"上鉤？你知道能夠引出侵蝕體的方法嗎？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"아주 간단한 일입니다. 전 오래전부터 그 녀석을 좇고 있었다고 말씀드리지 않았습니까?","JPN":"理屈は簡単です。私はずっと長い間、奴を追いかけてきたんですよ。","ENG":"It was very simple. Like I said, I've been chasing it for a long time.","TWN":"方法很簡單。我不是早就說過我一直在盯著那傢伙嗎？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"침식체는 가능성과 망집에 이끌립니다.","JPN":"侵食体は可能性や妄執に惹き付けられる。","ENG":"C.O.s are attracted to possibilities and obsessions.","TWN":"侵蝕體會被可能性和妄念所吸引。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그리고 이 황량한 사막에서 그걸 구할 방법은 간단하죠.","JPN":"そして、この荒廃した砂漠からその匂いを嗅ぎつけさせる手段は一つだけ。","ENG":"And there is one simple way to find them in is barren desert.","TWN":"而在這片荒涼的沙漠中，找到它的方法很簡單。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"바로 수많은 가능성을 지닌, 강력한 카운터를 데려오는 겁니다.","JPN":"それはたくさんの可能性を秘めた、強いカウンターを連れてくることです。","ENG":"It is to bring on a strong Counter who possesses countless possibilities.","TWN":"就是帶來擁有無限可能性的強大制裁者。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……처음부터 나를 미끼로 쓸 계획이었군.","JPN":"……最初から私を餌に使うつもりだったってことか。","ENG":"...So you were planning on using me as bait from the beginning.","TWN":"……竟然一開始就打算拿我當誘餌。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"대비는 충분합니다. 단지, 제가 포격을 할 때까지 고래의 공격을 견뎌내야 할 뿐이죠.","JPN":"備えは万全です。あとは、私が砲撃を撃つまでクジラの攻撃に耐えられるかどうかです。","ENG":"All preparations have been made. The catch is that you'll have to endure the whale's attacks until I open fire.","TWN":"現在已經萬事俱備，只要你們能撐到我發射炮擊。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그 말을 반드시 증명해야 할 거다.","JPN":"それが本当であることを願うぞ。","ENG":"You will have to prove those words.","TWN":"你最好要做到做到。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_NULL","text":{"KOREA":"도망칠 곳이 없어! 뒤에선 폭풍이 다가오고, 앞에선 포격이 쏟아진다고!","JPN":"逃げ場がない！　後方には砂嵐が、前方からは砲撃の嵐だ！","ENG":"There's nowhere to run! The sandstorm is approaching from the back, and bombs are pouring down in the front!","TWN":"沒地方逃了！後有沙塵暴逼近，前有炮火連天！"},"stage":{"bg":"VARUNA_04_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_NULL","text":{"KOREA":"흐, 흐아악! 내 다리! 누, 누가 내 다리 좀 갖고 와줘!","JPN":"あ、あがぁっ！　脚が！　誰か俺の脚を拾ってきてくれ！","ENG":"A-aarrgh! My leg! S-someone get my leg for me!","TWN":"呃啊啊！我的腿！誰，誰幫我把腿拿回來！"},"stage":{"bg":"VARUNA_04_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_NULL","text":{"KOREA":"사람들의 목소리가 들려. 사람들의 목소리가 나를 부르고 있어…….","JPN":"誰かの声が聞こえる。俺を呼ぶ声が……","ENG":"I hear their voices. They're calling me...","TWN":"我有聽到人的聲音，有人在呼喚我們……"},"stage":{"bg":"VARUNA_04_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"젠장.","JPN":"くそっ。","ENG":"Dammit.","TWN":"該死。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아합! 포격은 아직인가?","JPN":"アハブ！　砲撃はまだか？","ENG":"Ahab! How much longer until you open fire?","TWN":"亞哈！炮擊還沒開始嗎？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"이대로라면 희생자가 늘어난다! 지금쯤이면 준비가 완료되었을 텐데?","JPN":"このままでは犠牲者がさらに増えるぞ！　そろそろ準備はできてるはずだ！","ENG":"The number of casualties will increase at this rate! Shouldn't it be ready by now?!","TWN":"這樣下去會有更多的犧牲者！現在應該已經準備好了吧？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};